package main

import (
	"fmt"
	"log"
	"net/http"
)

func handler(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		log.Printf("Error reading request body: %v", err)
		return
	}

	// Close the request body so it can be read by the client
	r.Body.Close()

	// Print the request content
	fmt.Fprintf(w, "Request content: %s", body)

	// Log the request content
	log.Printf("Request content: %s", body)
}

func main() {
	http.HandleFunc("/", handler)
	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

This program sets up a simple HTTP server that logs and prints the content of the request body to the server's log and also back to the client. Make sure to import the `ioutil` package for reading the request body and handle potential errors appropriately.

